import { useLayoutEffect, useState } from "react";
import { getConsumedSparePartsData } from "../../../../../api";
import { useSetRecoilState } from "recoil";
import { Notification } from "../../../../../modules/global/global-states";

type sparePart = {
  id: number;
  code: string;
  description: string;
  brand: string;
  model: string;
  hospital: string;
  currentQuantity: string;
  requiredQuantity: number;
};

export function useSparePartsTableHooks() {
  const setNotification = useSetRecoilState(Notification);
  const [sparePartsData, setSparePartsData] = useState<sparePart[]>([]);
  useLayoutEffect(() => {
    getConsumedSparePartsData()
      .then((res) => {
        setSparePartsData(res);
      })
      .catch((err) => {
        setNotification({
          title: "Error fetching spare parts data",
          message: JSON.stringify(err),
          level: 2,
        });
      });
  }, [setNotification]);
  return sparePartsData;
}
